namespace sv_c1673b9b12f34561ae05666634e4a346.Components;

public enum ScreenSize
{
    Mobile,
    Tablet,
    Desktop
}

@implements IAsyncDisposable
@inject IJSRuntime JS

<CascadingValue Value="CurrentScreenSize">
    @ChildContent
</CascadingValue>

@code {
    [Parameter]
    public RenderFragment? ChildContent { get; set; }

    private ScreenSize CurrentScreenSize { get; set; } = ScreenSize.Desktop;

    private IJSObjectReference? _module;
    private DotNetObjectReference<ScreenSizeProvider>? _dotNetRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/ScreenSizeProvider.razor.js");
            await _module.InvokeVoidAsync("initialize", _dotNetRef);
        }
    }

    [JSInvokable]
    public void OnViewportWidthChanged(int width)
    {
        var newSize = width switch
        {
            < 768 => ScreenSize.Mobile,
            < 1024 => ScreenSize.Tablet,
            _ => ScreenSize.Desktop
        };

        if (newSize != CurrentScreenSize)
        {
            CurrentScreenSize = newSize;
            StateHasChanged();
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            await _module.InvokeVoidAsync("dispose");
            await _module.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }
}

let resizeHandler = null;

export function initialize(dotNetRef) {
    dotNetRef.invokeMethodAsync('OnViewportWidthChanged', window.innerWidth);

    resizeHandler = () => {
        dotNetRef.invokeMethodAsync('OnViewportWidthChanged', window.innerWidth);
    };
    window.addEventListener('resize', resizeHandler);
}

export function dispose() {
    if (resizeHandler) {
        window.removeEventListener('resize', resizeHandler);
        resizeHandler = null;
    }
}

